module priority_encoder_4bit (
    input wire [3:0] obf_in,
    output wire [1:0] out,
    output wire valid
);

    assign valid = |obf_in;
    assign out = (obf_in[3] ? 2'b11 :
                 (obf_in[2] ? 2'b10 :
                 (obf_in[1] ? 2'b01 :
                 (obf_in[0] ? 2'b00 : 2'b00))));

endmodule
